import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class CommandInjectionFixed {

    public static void main(String[] args) {
        try {
            System.out.print("Enter a website to ping: ");
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
            String website = reader.readLine();

            // Validate input to ensure it only contains alphanumeric characters and dots
            if (!website.matches("[a-zA-Z0-9.]+")) {
                System.out.println("Invalid input. Please provide a valid website name.");
                return;
            }

            Process p = Runtime.getRuntime().exec("ping " + website);

            BufferedReader input = new BufferedReader(new InputStreamReader(p.getInputStream()));
            String line;
            while ((line = input.readLine()) != null) {
                System.out.println(line);
            }

        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

